<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'
import { ElMessage, ElMessageBox } from 'element-plus'
import { api, errorMessage } from '@/api/client'
import { useAuthStore } from '@/stores/auth'
import { businessText, resourceText } from '@/utils/status'
const auth = useAuthStore()
const rows = ref<any[]>([])
const dialog = ref(false)
const editing = ref<number | null>(null)
const loading = ref(false)
const empty = () => ({ name: '', resource_type: 'rem', business_code: 'fut_mm', host: '', ssh_port: 22, username: '', auth_type: 'password', password: '', private_key: '', remote_path: '', capabilities: {}, version_info: '', notes: '', is_enabled: true })
const form = reactive<any>(empty())
async function load() { rows.value = (await api.get('/resources')).data }
function open(row?: any) { Object.assign(form, empty(), row || {}); form.password = ''; form.private_key = ''; editing.value = row?.id || null; dialog.value = true }
async function save() { loading.value = true; try { if (editing.value) await api.put(`/resources/${editing.value}`, form); else await api.post('/resources', form); ElMessage.success('已保存'); dialog.value = false; load() } catch (e) { ElMessage.error(errorMessage(e)) } finally { loading.value = false } }
async function health(row: any) { try { const { data } = await api.post(`/resources/${row.id}/health`); data.ok ? ElMessage.success(data.message) : ElMessage.error(data.message); load() } catch (e) { ElMessage.error(errorMessage(e)) } }
async function remove(row: any) { await ElMessageBox.confirm(`确定删除资源“${row.name}”？`, '删除确认', { type: 'warning' }); try { await api.delete(`/resources/${row.id}`); ElMessage.success('已删除'); load() } catch (e) { ElMessage.error(errorMessage(e)) } }
onMounted(load)
</script>
<template><div class="page"><div class="page-header"><div><h1 class="page-title">资源管理</h1><p class="muted">统一管理 REM、模拟市场、发单、抓包和 Coco 节点</p></div><el-button v-if="auth.isAdmin" type="primary" @click="open()">新增资源</el-button></div><div class="card"><el-table :data="rows"><el-table-column prop="name" label="名称" min-width="150"/><el-table-column label="类型"><template #default="s">{{resourceText[s.row.resource_type]}}</template></el-table-column><el-table-column label="业务" min-width="130"><template #default="s">{{businessText[s.row.business_code]}}</template></el-table-column><el-table-column label="连接地址" min-width="180"><template #default="s"><span class="mono">{{s.row.username}}@{{s.row.host}}:{{s.row.ssh_port}}</span></template></el-table-column><el-table-column label="健康"><template #default="s"><el-tag :type="s.row.health_status==='healthy'?'success':s.row.health_status==='unhealthy'?'danger':'info'" effect="plain">{{s.row.health_status}}</el-tag></template></el-table-column><el-table-column label="启用"><template #default="s"><el-tag :type="s.row.is_enabled?'success':'info'">{{s.row.is_enabled?'是':'否'}}</el-tag></template></el-table-column><el-table-column label="操作" width="210"><template #default="s"><el-button link type="primary" @click="health(s.row)">连通测试</el-button><template v-if="auth.isAdmin"><el-button link @click="open(s.row)">编辑</el-button><el-button link type="danger" @click="remove(s.row)">删除</el-button></template></template></el-table-column></el-table></div><el-dialog v-model="dialog" :title="editing?'编辑资源':'新增资源'" width="680px"><el-form :model="form" label-width="100px"><el-row :gutter="16"><el-col :span="12"><el-form-item label="名称"><el-input v-model="form.name"/></el-form-item></el-col><el-col :span="12"><el-form-item label="类型"><el-select v-model="form.resource_type" style="width:100%"><el-option v-for="(v,k) in resourceText" :key="k" :label="v" :value="k"/></el-select></el-form-item></el-col><el-col :span="12"><el-form-item label="所属业务"><el-select v-model="form.business_code" style="width:100%"><el-option v-for="(v,k) in businessText" :key="k" :label="v" :value="k"/></el-select></el-form-item></el-col><el-col :span="12"><el-form-item label="Linux 地址"><el-input v-model="form.host"/></el-form-item></el-col><el-col :span="12"><el-form-item label="SSH 端口"><el-input-number v-model="form.ssh_port" :min="1" :max="65535"/></el-form-item></el-col><el-col :span="12"><el-form-item label="用户名"><el-input v-model="form.username"/></el-form-item></el-col><el-col :span="12"><el-form-item label="认证方式"><el-radio-group v-model="form.auth_type"><el-radio-button value="password">密码</el-radio-button><el-radio-button value="private_key">私钥</el-radio-button></el-radio-group></el-form-item></el-col><el-col :span="12"><el-form-item :label="form.auth_type==='password'?'密码':'私钥'"><el-input v-if="form.auth_type==='password'" v-model="form.password" type="password" show-password :placeholder="editing?'留空保持原值':''"/><el-input v-else v-model="form.private_key" type="textarea" :rows="2"/></el-form-item></el-col><el-col :span="24"><el-form-item label="远端路径"><el-input v-model="form.remote_path"/></el-form-item></el-col><el-col :span="24"><el-form-item label="备注"><el-input v-model="form.notes" type="textarea"/></el-form-item></el-col></el-row></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" :loading="loading" @click="save">保存</el-button></template></el-dialog></div></template>
